    // ── Device-based inode read tests ──────────────────────────────────

    /// Build an ext4 image with a valid group descriptor and a root inode.
    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image_with_inode() -> Vec<u8> {
        let block_size: u32 = 4096;
        let image_size: u32 = 256 * 1024; // 256K = 64 blocks
        let mut image = vec![0_u8; image_size as usize];
        let sb_off = EXT4_SUPERBLOCK_OFFSET;

        // ── Superblock ──
        image[sb_off + 0x38..sb_off + 0x3A].copy_from_slice(&EXT4_SUPER_MAGIC.to_le_bytes());
        image[sb_off + 0x18..sb_off + 0x1C].copy_from_slice(&2_u32.to_le_bytes()); // log=2 → 4K
        let blocks_count = image_size / block_size;
        image[sb_off + 0x04..sb_off + 0x08].copy_from_slice(&blocks_count.to_le_bytes());
        image[sb_off..sb_off + 0x04].copy_from_slice(&128_u32.to_le_bytes()); // inodes_count
        image[sb_off + 0x14..sb_off + 0x18].copy_from_slice(&0_u32.to_le_bytes()); // first_data_block
        image[sb_off + 0x20..sb_off + 0x24].copy_from_slice(&blocks_count.to_le_bytes()); // blocks_per_group
        image[sb_off + 0x28..sb_off + 0x2C].copy_from_slice(&128_u32.to_le_bytes()); // inodes_per_group
        image[sb_off + 0x58..sb_off + 0x5A].copy_from_slice(&256_u16.to_le_bytes()); // inode_size
        image[sb_off + 0x4C..sb_off + 0x50].copy_from_slice(&1_u32.to_le_bytes()); // rev_level=DYNAMIC
        let incompat: u32 = 0x0002 | 0x0040; // FILETYPE | EXTENTS
        image[sb_off + 0x60..sb_off + 0x64].copy_from_slice(&incompat.to_le_bytes());
        image[sb_off + 0x54..sb_off + 0x58].copy_from_slice(&11_u32.to_le_bytes()); // first_ino

        // ── Group descriptor at block 1 (offset 4096) ──
        // 32-byte group descriptor (no 64BIT feature).
        let gd_off: usize = 4096;
        // bg_block_bitmap = block 2
        image[gd_off..gd_off + 4].copy_from_slice(&2_u32.to_le_bytes());
        // bg_inode_bitmap = block 3
        image[gd_off + 4..gd_off + 8].copy_from_slice(&3_u32.to_le_bytes());
        // bg_inode_table = block 4 (offset 16384)
        image[gd_off + 8..gd_off + 12].copy_from_slice(&4_u32.to_le_bytes());

        // ── Root inode (#2) in the inode table ──
        // Inode 2 is at index 1 (0-based) in the table.
        // offset = 16384 + 1 * 256 = 16640
        let ino_off: usize = 16384 + 256;
        // mode = S_IFDIR | 0o755
        let mode: u16 = 0o040_755;
        image[ino_off..ino_off + 2].copy_from_slice(&mode.to_le_bytes());
        // uid_lo = 0
        image[ino_off + 2..ino_off + 4].copy_from_slice(&0_u16.to_le_bytes());
        // size = 4096
        image[ino_off + 4..ino_off + 8].copy_from_slice(&4096_u32.to_le_bytes());
        // links_count = 2
        image[ino_off + 0x1A..ino_off + 0x1C].copy_from_slice(&2_u16.to_le_bytes());
        // i_extra_isize = 32 (for 256-byte inodes, extra area starts at 128)
        image[ino_off + 0x80..ino_off + 0x82].copy_from_slice(&32_u16.to_le_bytes());

        image
    }

    fn set_group_desc_free_counts(image: &mut [u8], free_blocks: u16, free_inodes: u16) {
        let gd_off: usize = 4096;
        image[gd_off + 0x0C..gd_off + 0x0E].copy_from_slice(&free_blocks.to_le_bytes());
        image[gd_off + 0x0E..gd_off + 0x10].copy_from_slice(&free_inodes.to_le_bytes());
    }

    fn write_jbd2_header(block: &mut [u8], block_type: u32, sequence: u32) {
        const JBD2_MAGIC: u32 = 0xC03B_3998;
        block[0..4].copy_from_slice(&JBD2_MAGIC.to_be_bytes());
        block[4..8].copy_from_slice(&block_type.to_be_bytes());
        block[8..12].copy_from_slice(&sequence.to_be_bytes());
    }

    #[allow(clippy::too_many_arguments)]
    fn write_jbd2_superblock_v2(
        block: &mut [u8],
        block_size: u32,
        max_len: u32,
        first_log_block: u32,
        start_sequence: u32,
        start_block: u32,
        num_fc_blocks: u32,
        feature_incompat: u32,
    ) {
        write_jbd2_header(block, 4, 0);
        block[12..16].copy_from_slice(&block_size.to_be_bytes());
        block[16..20].copy_from_slice(&max_len.to_be_bytes());
        block[20..24].copy_from_slice(&first_log_block.to_be_bytes());
        block[24..28].copy_from_slice(&start_sequence.to_be_bytes());
        block[28..32].copy_from_slice(&start_block.to_be_bytes());
        block[40..44].copy_from_slice(&feature_incompat.to_be_bytes());
        block[84..88].copy_from_slice(&num_fc_blocks.to_be_bytes());
    }

    fn checksum_jbd2_tail_zeroed_block_for_test(block: &[u8], seed: u32) -> u32 {
        let tail = block.len() - 4;
        let checksum = ffs_types::crc32c_append(!seed, &block[..tail]);
        let checksum = ffs_types::crc32c_append(checksum, &[0_u8; 4]);
        !checksum
    }

    fn stamp_test_jbd2_descriptor_checksum(block: &mut [u8], seed: u32) {
        let checksum = checksum_jbd2_tail_zeroed_block_for_test(block, seed);
        let tail = block.len() - 4;
        block[tail..tail + 4].copy_from_slice(&checksum.to_be_bytes());
    }

    fn stamp_test_jbd2_commit_checksum(block: &mut [u8], seed: u32) {
        const JBD2_COMMIT_CHKSUM_OFFSET: usize = 16;

        let mut temp = block.to_vec();
        temp[JBD2_COMMIT_CHKSUM_OFFSET..JBD2_COMMIT_CHKSUM_OFFSET + 4].fill(0);
        let checksum = !ffs_types::crc32c_append(!seed, &temp);
        block[JBD2_COMMIT_CHKSUM_OFFSET..JBD2_COMMIT_CHKSUM_OFFSET + 4]
            .copy_from_slice(&checksum.to_be_bytes());
    }

    fn checksum_jbd2_data_block_for_test(block: &[u8], sequence: u32, seed: u32) -> u32 {
        let sequence = sequence.to_be_bytes();
        let checksum = ffs_types::crc32c_append(!seed, &sequence);
        !ffs_types::crc32c_append(checksum, block)
    }

    fn stamp_test_jbd2_csum3_tag_checksum(
        descriptor_block: &mut [u8],
        tag_offset: usize,
        data_block: &[u8],
        sequence: u32,
        seed: u32,
    ) {
        let checksum = checksum_jbd2_data_block_for_test(data_block, sequence, seed);
        descriptor_block[tag_offset + 12..tag_offset + 16].copy_from_slice(&checksum.to_be_bytes());
    }

    fn jbd2_v3_seed(uuid: [u8; 16]) -> u32 {
        !ffs_types::crc32c_append(!0u32, &uuid)
    }

    fn build_fc_tag(tag_type: u16, payload: &[u8]) -> Vec<u8> {
        let mut bytes = Vec::with_capacity(4 + payload.len());
        bytes.extend_from_slice(&tag_type.to_le_bytes());
        bytes.extend_from_slice(
            &u16::try_from(payload.len())
                .expect("fast-commit payload length should fit")
                .to_le_bytes(),
        );
        bytes.extend_from_slice(payload);
        bytes
    }

    fn build_fc_inode_update_transaction(ino: u32, tid: u32) -> Vec<u8> {
        let mut bytes = Vec::new();
        bytes.extend(build_fc_tag(0x0A, &[0; 16]));
        bytes.extend(build_fc_tag(0x07, &ino.to_le_bytes()));
        let mut tail = [0_u8; 8];
        tail[..4].copy_from_slice(&tid.to_le_bytes());
        bytes.extend(build_fc_tag(0x09, &tail));
        bytes
    }

    fn build_fc_create_transaction(parent_ino: u32, ino: u32, name: &[u8], tid: u32) -> Vec<u8> {
        let mut bytes = Vec::new();
        bytes.extend(build_fc_tag(0x0A, &[0; 16]));
        let mut payload = Vec::with_capacity(8 + name.len());
        payload.extend_from_slice(&parent_ino.to_le_bytes());
        payload.extend_from_slice(&ino.to_le_bytes());
        payload.extend_from_slice(name);
        bytes.extend(build_fc_tag(0x05, &payload));
        let mut tail = [0_u8; 8];
        tail[..4].copy_from_slice(&tid.to_le_bytes());
        bytes.extend(build_fc_tag(0x09, &tail));
        bytes
    }

    fn pad_fc_stream_to_block_boundary(bytes: &mut Vec<u8>, block_len: usize) {
        let used = bytes.len() % block_len;
        if used == 0 {
            return;
        }

        let remaining = block_len - used;
        let pad_tag = build_fc_tag(0x08, &[]);
        debug_assert_eq!(pad_tag.len(), 4);
        for _ in 0..(remaining / pad_tag.len()) {
            bytes.extend_from_slice(&pad_tag);
        }
    }

    fn set_test_journal_uuid(image: &mut [u8], uuid: [u8; 16]) {
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        image[sb_off + 0xD0..sb_off + 0xE0].copy_from_slice(&uuid);
    }

    fn build_external_journal_image(
        block_size: usize,
        uuid: [u8; 16],
        target_block: u32,
        payload: &[u8],
    ) -> Vec<u8> {
        let blocks = 8usize;
        let mut image = vec![0u8; block_size * blocks];
        write_jbd2_superblock_v2(
            &mut image[..block_size],
            u32::try_from(block_size).expect("block_size fits u32"),
            u32::try_from(blocks).expect("block count fits u32"),
            1,
            1,
            1,
            0,
            0,
        );
        image[48..64].copy_from_slice(&uuid);

        let desc = block_size;
        write_jbd2_header(&mut image[desc..desc + block_size], 1, 1);
        image[desc + 12..desc + 16].copy_from_slice(&target_block.to_be_bytes());
        image[desc + 16..desc + 20].copy_from_slice(&0x0000_0008_u32.to_be_bytes());

        let data = 2 * block_size;
        image[data..data + payload.len()].copy_from_slice(payload);

        let commit = 3 * block_size;
        write_jbd2_header(&mut image[commit..commit + block_size], 2, 1);

        image
    }

    /// Build an ext4 image with an internal journal inode and one committed
    /// JBD2 transaction that rewrites block 15.
    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image_with_internal_journal() -> Vec<u8> {
        let mut image = build_ext4_image_with_extents();
        let sb_off = EXT4_SUPERBLOCK_OFFSET;

        // Enable HAS_JOURNAL and point to internal journal inode #8.
        let compat = u32::from_le_bytes([
            image[sb_off + 0x5C],
            image[sb_off + 0x5D],
            image[sb_off + 0x5E],
            image[sb_off + 0x5F],
        ]);
        image[sb_off + 0x5C..sb_off + 0x60].copy_from_slice(&(compat | 0x0004).to_le_bytes());
        image[sb_off + 0xE0..sb_off + 0xE4].copy_from_slice(&8_u32.to_le_bytes());

        // Inode #8 (index 7) -> journal extent [block 20..=22].
        let ino8_off: usize = 4 * 4096 + 7 * 256;
        image[ino8_off..ino8_off + 2].copy_from_slice(&0o100_600_u16.to_le_bytes());
        image[ino8_off + 4..ino8_off + 8].copy_from_slice(&(3_u32 * 4096).to_le_bytes());
        image[ino8_off + 0x1A..ino8_off + 0x1C].copy_from_slice(&1_u16.to_le_bytes());
        image[ino8_off + 0x20..ino8_off + 0x24].copy_from_slice(&0x0008_0000_u32.to_le_bytes());
        image[ino8_off + 0x80..ino8_off + 0x82].copy_from_slice(&32_u16.to_le_bytes());

        let e = ino8_off + 0x28;
        image[e..e + 2].copy_from_slice(&0xF30A_u16.to_le_bytes()); // extent magic
        image[e + 2..e + 4].copy_from_slice(&1_u16.to_le_bytes()); // entries
        image[e + 4..e + 6].copy_from_slice(&4_u16.to_le_bytes()); // max
        image[e + 6..e + 8].copy_from_slice(&0_u16.to_le_bytes()); // depth=0
        image[e + 12..e + 16].copy_from_slice(&0_u32.to_le_bytes()); // logical 0
        image[e + 16..e + 18].copy_from_slice(&3_u16.to_le_bytes()); // len = 3 blocks
        image[e + 18..e + 20].copy_from_slice(&0_u16.to_le_bytes()); // start_hi
        image[e + 20..e + 24].copy_from_slice(&20_u32.to_le_bytes()); // start_lo

        // Journal block 20: descriptor, one tag to target block 15.
        let j_desc = 20 * 4096;
        write_jbd2_header(&mut image[j_desc..j_desc + 4096], 1, 1);
        image[j_desc + 12..j_desc + 16].copy_from_slice(&15_u32.to_be_bytes());
        image[j_desc + 16..j_desc + 20].copy_from_slice(&0x0000_0008_u32.to_be_bytes()); // LAST_TAG

        // Journal block 21: replay payload.
        let j_data = 21 * 4096;
        image[j_data..j_data + 16].copy_from_slice(b"JBD2-REPLAY-TEST");

        // Journal block 22: commit.
        let j_commit = 22 * 4096;
        write_jbd2_header(&mut image[j_commit..j_commit + 4096], 2, 1);

        image
    }

    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image_with_internal_journal_checksums(
        corrupt_descriptor_checksum: bool,
    ) -> Vec<u8> {
        const JBD2_FEATURE_INCOMPAT_CSUM_V3: u32 = 0x0000_0010;

        let mut image = build_ext4_image_with_extents();
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        let journal_uuid = *b"ffs-jbd2-csum-v3";
        let seed = jbd2_v3_seed(journal_uuid);

        let compat = u32::from_le_bytes([
            image[sb_off + 0x5C],
            image[sb_off + 0x5D],
            image[sb_off + 0x5E],
            image[sb_off + 0x5F],
        ]);
        image[sb_off + 0x5C..sb_off + 0x60].copy_from_slice(&(compat | 0x0004).to_le_bytes());
        image[sb_off + 0xE0..sb_off + 0xE4].copy_from_slice(&8_u32.to_le_bytes());

        let ino8_off: usize = 4 * 4096 + 7 * 256;
        image[ino8_off..ino8_off + 2].copy_from_slice(&0o100_600_u16.to_le_bytes());
        image[ino8_off + 4..ino8_off + 8].copy_from_slice(&(4_u32 * 4096).to_le_bytes());
        image[ino8_off + 0x1A..ino8_off + 0x1C].copy_from_slice(&1_u16.to_le_bytes());
        image[ino8_off + 0x20..ino8_off + 0x24].copy_from_slice(&0x0008_0000_u32.to_le_bytes());
        image[ino8_off + 0x80..ino8_off + 0x82].copy_from_slice(&32_u16.to_le_bytes());

        let e = ino8_off + 0x28;
        image[e..e + 2].copy_from_slice(&0xF30A_u16.to_le_bytes());
        image[e + 2..e + 4].copy_from_slice(&1_u16.to_le_bytes());
        image[e + 4..e + 6].copy_from_slice(&4_u16.to_le_bytes());
        image[e + 6..e + 8].copy_from_slice(&0_u16.to_le_bytes());
        image[e + 12..e + 16].copy_from_slice(&0_u32.to_le_bytes());
        image[e + 16..e + 18].copy_from_slice(&4_u16.to_le_bytes());
        image[e + 18..e + 20].copy_from_slice(&0_u16.to_le_bytes());
        image[e + 20..e + 24].copy_from_slice(&20_u32.to_le_bytes());

        let j_sb = 20 * 4096;
        write_jbd2_superblock_v2(
            &mut image[j_sb..j_sb + 4096],
            4096,
            4,
            1,
            1,
            1,
            0,
            JBD2_FEATURE_INCOMPAT_CSUM_V3,
        );
        image[j_sb + 48..j_sb + 64].copy_from_slice(&journal_uuid);

        let j_desc = 21 * 4096;
        write_jbd2_header(&mut image[j_desc..j_desc + 4096], 1, 1);
        image[j_desc + 12..j_desc + 16].copy_from_slice(&15_u32.to_be_bytes());
        image[j_desc + 16..j_desc + 20].copy_from_slice(&0x0000_0008_u32.to_be_bytes());

        let j_data = 22 * 4096;
        image[j_data..j_data + 16].copy_from_slice(b"JBD2-CSUM-REPLAY");

        let (descriptor_prefix, data_suffix) = image.split_at_mut(j_data);
        let descriptor = &mut descriptor_prefix[j_desc..j_desc + 4096];
        let data = &data_suffix[..4096];
        stamp_test_jbd2_csum3_tag_checksum(descriptor, 12, data, 1, seed);
        stamp_test_jbd2_descriptor_checksum(descriptor, seed);
        if corrupt_descriptor_checksum {
            descriptor[4096 - 1] ^= 0x5A;
        }

        let j_commit = 23 * 4096;
        write_jbd2_header(&mut image[j_commit..j_commit + 4096], 2, 1);
        stamp_test_jbd2_commit_checksum(&mut image[j_commit..j_commit + 4096], seed);

        image
    }

    /// Build an ext4 image with an internal journal inode backed by two
    /// non-contiguous extents and one committed JBD2 transaction that rewrites
    /// block 15.
    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image_with_non_contiguous_internal_journal() -> Vec<u8> {
        let mut image = build_ext4_image_with_extents();
        let sb_off = EXT4_SUPERBLOCK_OFFSET;

        // Enable HAS_JOURNAL and point to internal journal inode #8.
        let compat = u32::from_le_bytes([
            image[sb_off + 0x5C],
            image[sb_off + 0x5D],
            image[sb_off + 0x5E],
            image[sb_off + 0x5F],
        ]);
        image[sb_off + 0x5C..sb_off + 0x60].copy_from_slice(&(compat | 0x0004).to_le_bytes());
        image[sb_off + 0xE0..sb_off + 0xE4].copy_from_slice(&8_u32.to_le_bytes());

        // Inode #8 (index 7) -> journal extents:
        // logical [0..=1] -> physical [20..=21]
        // logical [2..=2] -> physical [40..=40]
        let ino8_off: usize = 4 * 4096 + 7 * 256;
        image[ino8_off..ino8_off + 2].copy_from_slice(&0o100_600_u16.to_le_bytes());
        image[ino8_off + 4..ino8_off + 8].copy_from_slice(&(3_u32 * 4096).to_le_bytes());
        image[ino8_off + 0x1A..ino8_off + 0x1C].copy_from_slice(&1_u16.to_le_bytes());
        image[ino8_off + 0x20..ino8_off + 0x24].copy_from_slice(&0x0008_0000_u32.to_le_bytes());
        image[ino8_off + 0x80..ino8_off + 0x82].copy_from_slice(&32_u16.to_le_bytes());

        let e = ino8_off + 0x28;
        image[e..e + 2].copy_from_slice(&0xF30A_u16.to_le_bytes()); // extent magic
        image[e + 2..e + 4].copy_from_slice(&2_u16.to_le_bytes()); // entries
        image[e + 4..e + 6].copy_from_slice(&4_u16.to_le_bytes()); // max
        image[e + 6..e + 8].copy_from_slice(&0_u16.to_le_bytes()); // depth=0

        // extent[0]: logical 0, len 2, start 20
        image[e + 12..e + 16].copy_from_slice(&0_u32.to_le_bytes());
        image[e + 16..e + 18].copy_from_slice(&2_u16.to_le_bytes());
        image[e + 18..e + 20].copy_from_slice(&0_u16.to_le_bytes());
        image[e + 20..e + 24].copy_from_slice(&20_u32.to_le_bytes());

        // extent[1]: logical 2, len 1, start 40
        image[e + 24..e + 28].copy_from_slice(&2_u32.to_le_bytes());
        image[e + 28..e + 30].copy_from_slice(&1_u16.to_le_bytes());
        image[e + 30..e + 32].copy_from_slice(&0_u16.to_le_bytes());
        image[e + 32..e + 36].copy_from_slice(&40_u32.to_le_bytes());

        // Journal block 20: descriptor, one tag to target block 15.
        let j_desc = 20 * 4096;
        write_jbd2_header(&mut image[j_desc..j_desc + 4096], 1, 1);
        image[j_desc + 12..j_desc + 16].copy_from_slice(&15_u32.to_be_bytes());
        image[j_desc + 16..j_desc + 20].copy_from_slice(&0x0000_0008_u32.to_be_bytes()); // LAST_TAG

        // Journal block 21: replay payload.
        let j_data = 21 * 4096;
        image[j_data..j_data + 16].copy_from_slice(b"JBD2-REPLAY-TEST");

        // Journal block 40: commit.
        let j_commit = 40 * 4096;
        write_jbd2_header(&mut image[j_commit..j_commit + 4096], 2, 1);

        image
    }

    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image_with_fast_commit_evidence() -> Vec<u8> {
        const JBD2_FEATURE_INCOMPAT_FAST_COMMIT: u32 = 0x0000_0020;
        const EXT4_COMPAT_FAST_COMMIT: u32 = 0x0000_0400;

        let mut image = build_ext4_image_with_extents();
        let sb_off = EXT4_SUPERBLOCK_OFFSET;

        let compat = u32::from_le_bytes([
            image[sb_off + 0x5C],
            image[sb_off + 0x5D],
            image[sb_off + 0x5E],
            image[sb_off + 0x5F],
        ]);
        image[sb_off + 0x5C..sb_off + 0x60]
            .copy_from_slice(&(compat | 0x0004 | EXT4_COMPAT_FAST_COMMIT).to_le_bytes());
        image[sb_off + 0xE0..sb_off + 0xE4].copy_from_slice(&8_u32.to_le_bytes());

        // Inode #8 -> journal extent [20..=25].
        let ino8_off: usize = 4 * 4096 + 7 * 256;
        image[ino8_off..ino8_off + 2].copy_from_slice(&0o100_600_u16.to_le_bytes());
        image[ino8_off + 4..ino8_off + 8].copy_from_slice(&(6_u32 * 4096).to_le_bytes());
        image[ino8_off + 0x1A..ino8_off + 0x1C].copy_from_slice(&1_u16.to_le_bytes());
        image[ino8_off + 0x20..ino8_off + 0x24].copy_from_slice(&0x0008_0000_u32.to_le_bytes());
        image[ino8_off + 0x80..ino8_off + 0x82].copy_from_slice(&32_u16.to_le_bytes());

        let e = ino8_off + 0x28;
        image[e..e + 2].copy_from_slice(&0xF30A_u16.to_le_bytes());
        image[e + 2..e + 4].copy_from_slice(&1_u16.to_le_bytes());
        image[e + 4..e + 6].copy_from_slice(&4_u16.to_le_bytes());
        image[e + 6..e + 8].copy_from_slice(&0_u16.to_le_bytes());
        image[e + 12..e + 16].copy_from_slice(&0_u32.to_le_bytes());
        image[e + 16..e + 18].copy_from_slice(&6_u16.to_le_bytes());
        image[e + 18..e + 20].copy_from_slice(&0_u16.to_le_bytes());
        image[e + 20..e + 24].copy_from_slice(&20_u32.to_le_bytes());

        let journal_sb = 20 * 4096;
        write_jbd2_superblock_v2(
            &mut image[journal_sb..journal_sb + 4096],
            4096,
            6,
            1,
            1,
            1,
            2,
            JBD2_FEATURE_INCOMPAT_FAST_COMMIT,
        );

        let j_desc = 21 * 4096;
        write_jbd2_header(&mut image[j_desc..j_desc + 4096], 1, 1);
        image[j_desc + 12..j_desc + 16].copy_from_slice(&15_u32.to_be_bytes());
        image[j_desc + 16..j_desc + 20].copy_from_slice(&0x0000_0008_u32.to_be_bytes());

        let j_data = 22 * 4096;
        image[j_data..j_data + 16].copy_from_slice(b"JBD2-REPLAY-TEST");

        let j_commit = 23 * 4096;
        write_jbd2_header(&mut image[j_commit..j_commit + 4096], 2, 1);

        let fc_payload = build_fc_inode_update_transaction(42, 1);
        let fc_block = 24 * 4096;
        image[fc_block..fc_block + fc_payload.len()].copy_from_slice(&fc_payload);

        image
    }

    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image_with_truncated_fast_commit_evidence() -> Vec<u8> {
        let mut image = build_ext4_image_with_fast_commit_evidence();
        let fc_block = 24 * 4096;
        let mut truncated = Vec::new();
        truncated.extend(build_fc_tag(0x0A, &[0; 16]));
        truncated.extend(build_fc_tag(0x07, &42_u32.to_le_bytes()));
        image[fc_block..fc_block + 4096].fill(0);
        image[fc_block..fc_block + truncated.len()].copy_from_slice(&truncated);
        image
    }

    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image_with_multi_block_fast_commit_evidence() -> Vec<u8> {
        let mut image = build_ext4_image_with_fast_commit_evidence();
        let fc_block = 24 * 4096;
        let mut first_fc_payload = build_fc_inode_update_transaction(42, 1);
        pad_fc_stream_to_block_boundary(&mut first_fc_payload, 4096);
        image[fc_block..fc_block + 4096].fill(0);
        image[fc_block..fc_block + 4096].copy_from_slice(&first_fc_payload);

        let second_fc_payload = build_fc_inode_update_transaction(43, 2);

        let second_fc_block = 25 * 4096;
        image[second_fc_block..second_fc_block + second_fc_payload.len()]
            .copy_from_slice(&second_fc_payload);
        image
    }

    #[allow(clippy::cast_possible_truncation)]
    fn build_ext4_image_with_fast_commit_create_evidence() -> Vec<u8> {
        let mut image = build_ext4_image_with_fast_commit_evidence();

        let root_ino = 4 * 4096 + 256;
        image[root_ino..root_ino + 2].copy_from_slice(&0o040_755_u16.to_le_bytes());
        image[root_ino + 4..root_ino + 8].copy_from_slice(&4096_u32.to_le_bytes());
        image[root_ino + 0x1A..root_ino + 0x1C].copy_from_slice(&3_u16.to_le_bytes());
        image[root_ino + 0x20..root_ino + 0x24].copy_from_slice(&0x0008_0000_u32.to_le_bytes());
        image[root_ino + 0x80..root_ino + 0x82].copy_from_slice(&32_u16.to_le_bytes());

        let root_extent = root_ino + 0x28;
        image[root_extent..root_extent + 2].copy_from_slice(&0xF30A_u16.to_le_bytes());
        image[root_extent + 2..root_extent + 4].copy_from_slice(&1_u16.to_le_bytes());
        image[root_extent + 4..root_extent + 6].copy_from_slice(&4_u16.to_le_bytes());
        image[root_extent + 6..root_extent + 8].copy_from_slice(&0_u16.to_le_bytes());
        image[root_extent + 12..root_extent + 16].copy_from_slice(&0_u32.to_le_bytes());
        image[root_extent + 16..root_extent + 18].copy_from_slice(&1_u16.to_le_bytes());
        image[root_extent + 18..root_extent + 20].copy_from_slice(&0_u16.to_le_bytes());
        image[root_extent + 20..root_extent + 24].copy_from_slice(&10_u32.to_le_bytes());

        let dir_block = 10 * 4096;
        image[dir_block..dir_block + 4].copy_from_slice(&2_u32.to_le_bytes());
        image[dir_block + 4..dir_block + 6].copy_from_slice(&12_u16.to_le_bytes());
        image[dir_block + 6] = 1;
        image[dir_block + 7] = 2;
        image[dir_block + 8] = b'.';

        let dotdot = dir_block + 12;
        image[dotdot..dotdot + 4].copy_from_slice(&2_u32.to_le_bytes());
        image[dotdot + 4..dotdot + 6].copy_from_slice(&12_u16.to_le_bytes());
        image[dotdot + 6] = 2;
        image[dotdot + 7] = 2;
        image[dotdot + 8] = b'.';
        image[dotdot + 9] = b'.';

        let hello = dotdot + 12;
        image[hello..hello + 4].copy_from_slice(&11_u32.to_le_bytes());
        image[hello + 4..hello + 6].copy_from_slice(&(4096_u16 - 24).to_le_bytes());
        image[hello + 6] = 9;
        image[hello + 7] = 1;
        image[hello + 8..hello + 17].copy_from_slice(b"hello.txt");

        let fc_block = 24 * 4096;
        let fc_payload = build_fc_create_transaction(2, 11, b"hello.txt", 1);
        image[fc_block..fc_block + 4096].fill(0);
        image[fc_block..fc_block + fc_payload.len()].copy_from_slice(&fc_payload);
        image
    }

    fn build_fscrypt_context_v1(
        contents_mode: u8,
        filenames_mode: u8,
        flags: u8,
        descriptor: [u8; 8],
        nonce: [u8; 16],
    ) -> Vec<u8> {
        let mut context = Vec::with_capacity(FSCRYPT_CONTEXT_V1_SIZE);
        context.push(FSCRYPT_POLICY_V1_VERSION);
        context.push(contents_mode);
        context.push(filenames_mode);
        context.push(flags);
        context.extend_from_slice(&descriptor);
        context.extend_from_slice(&nonce);
        context
    }

    fn build_fscrypt_context_v2(
        contents_mode: u8,
        filenames_mode: u8,
        flags: u8,
        log2_data_unit_size: u8,
        identifier: [u8; 16],
        nonce: [u8; 16],
    ) -> Vec<u8> {
        let mut context = Vec::with_capacity(FSCRYPT_CONTEXT_V2_SIZE);
        context.push(FSCRYPT_POLICY_V2_VERSION);
        context.push(contents_mode);
        context.push(filenames_mode);
        context.push(flags);
        context.push(log2_data_unit_size);
        context.extend_from_slice(&[0_u8; 3]);
        context.extend_from_slice(&identifier);
        context.extend_from_slice(&nonce);
        context
    }

    fn test_inode_offset(ino: u32) -> usize {
        assert!(ino > 0, "inode numbers are 1-based");
        let inode_index = usize::try_from(ino.saturating_sub(1)).expect("inode index should fit");
        4 * 4096 + inode_index * 256
    }

    fn set_test_inode_dtime(image: &mut [u8], ino: u32, next: u32) {
        let inode_off = test_inode_offset(ino);
        image[inode_off + 0x14..inode_off + 0x18].copy_from_slice(&next.to_le_bytes());
    }

    fn set_test_inode_links_count(image: &mut [u8], ino: u32, links_count: u16) {
        let inode_off = test_inode_offset(ino);
        image[inode_off + 0x1A..inode_off + 0x1C].copy_from_slice(&links_count.to_le_bytes());
    }

    fn set_test_ext4_state(image: &mut [u8], state: u16) {
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        image[sb_off + 0x3A..sb_off + 0x3C].copy_from_slice(&state.to_le_bytes());
    }

    fn build_test_inline_ibody(ibody_len: usize, entries: &[ffs_ondisk::Ext4Xattr]) -> Vec<u8> {
        let mut out = vec![0_u8; ibody_len];
        if entries.is_empty() {
            return out;
        }

        out[0..4].copy_from_slice(&ffs_types::EXT4_XATTR_MAGIC.to_le_bytes());
        let region_capacity = ibody_len
            .checked_sub(4)
            .expect("inline xattr region must include 4-byte header");
        let mut region = vec![0_u8; region_capacity];
        let mut next_entry = 0_usize;
        let mut value_tail = region_capacity;

        for entry in entries {
            let entry_len = (16 + entry.name.len() + 3) & !3;
            let value_start = value_tail
                .checked_sub(entry.value.len())
                .expect("inline xattr value should fit")
                & !3;
            let entry_end_with_term = next_entry
                .checked_add(entry_len + 4)
                .expect("inline xattr entry offset should not overflow");
            assert!(
                entry_end_with_term <= value_start,
                "inline xattr entry table should not overlap values"
            );

            region[value_start..value_start + entry.value.len()].copy_from_slice(&entry.value);
            value_tail = value_start;

            region[next_entry] =
                u8::try_from(entry.name.len()).expect("inline xattr name should fit in u8");
            region[next_entry + 1] = entry.name_index;
            region[next_entry + 2..next_entry + 4].copy_from_slice(
                &u16::try_from(value_start)
                    .expect("inline xattr value offset should fit in u16")
                    .to_le_bytes(),
            );
            region[next_entry + 8..next_entry + 12].copy_from_slice(
                &u32::try_from(entry.value.len())
                    .expect("inline xattr value length should fit in u32")
                    .to_le_bytes(),
            );
            region[next_entry + 16..next_entry + 16 + entry.name.len()]
                .copy_from_slice(&entry.name);
            next_entry += entry_len;
        }

        out[4..].copy_from_slice(&region);
        out
    }

    fn build_test_stored_posix_acl(entries: &[(u16, u16)]) -> Vec<u8> {
        let mut out = Vec::with_capacity(4 + (entries.len() * 4));
        out.extend_from_slice(&EXT4_POSIX_ACL_STORAGE_VERSION.to_le_bytes());
        for (tag, perm) in entries {
            out.extend_from_slice(&tag.to_le_bytes());
            out.extend_from_slice(&perm.to_le_bytes());
        }
        out
    }

    fn build_ext4_image_with_encryption_context(context: &[u8], encrypted_flag: bool) -> Vec<u8> {
        let mut image = build_ext4_image_with_inode();
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        let incompat = u32::from_le_bytes([
            image[sb_off + 0x60],
            image[sb_off + 0x61],
            image[sb_off + 0x62],
            image[sb_off + 0x63],
        ]);
        image[sb_off + 0x60..sb_off + 0x64].copy_from_slice(
            &(incompat | ffs_ondisk::Ext4IncompatFeatures::ENCRYPT.0).to_le_bytes(),
        );

        let ino_off = test_inode_offset(11);
        image[ino_off..ino_off + 2].copy_from_slice(&(ffs_types::S_IFREG | 0o600).to_le_bytes());
        image[ino_off + 0x1A..ino_off + 0x1C].copy_from_slice(&1_u16.to_le_bytes());
        image[ino_off + 0x80..ino_off + 0x82].copy_from_slice(&32_u16.to_le_bytes());
        if encrypted_flag {
            image[ino_off + 0x20..ino_off + 0x24].copy_from_slice(&0x0000_0800_u32.to_le_bytes());
        }

        let ibody = build_test_inline_ibody(
            256 - (128 + 32),
            &[ffs_ondisk::Ext4Xattr {
                name_index: ffs_types::EXT4_XATTR_INDEX_ENCRYPTION,
                name: EXT4_ENCRYPTION_XATTR_NAME.to_vec(),
                value: context.to_vec(),
            }],
        );
        let xattr_off = ino_off + 128 + 32;
        image[xattr_off..xattr_off + ibody.len()].copy_from_slice(&ibody);

        let ibm = 3 * 4096;
        let bit = 10_usize;
        image[ibm + bit / 8] |= 1 << (bit % 8);
        image
    }

    fn build_ext4_image_with_posix_acl_xattr(value: &[u8], name_index: u8) -> Vec<u8> {
        let mut image = build_ext4_image_with_inode();
        let ino_off = test_inode_offset(11);
        image[ino_off..ino_off + 2].copy_from_slice(&(ffs_types::S_IFREG | 0o600).to_le_bytes());
        image[ino_off + 0x1A..ino_off + 0x1C].copy_from_slice(&1_u16.to_le_bytes());
        image[ino_off + 0x80..ino_off + 0x82].copy_from_slice(&32_u16.to_le_bytes());

        let ibody = build_test_inline_ibody(
            256 - (128 + 32),
            &[ffs_ondisk::Ext4Xattr {
                name_index,
                name: Vec::new(),
                value: value.to_vec(),
            }],
        );
        let xattr_off = ino_off + 128 + 32;
        image[xattr_off..xattr_off + ibody.len()].copy_from_slice(&ibody);

        let ibm = 3 * 4096;
        let bit = 10_usize;
        image[ibm + bit / 8] |= 1 << (bit % 8);
        image
    }

    fn build_ext4_image_with_orphan_chain(chain: &[u32]) -> Vec<u8> {
        let mut image = build_ext4_image_with_extents();
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        let head = chain.first().copied().unwrap_or(0);
        image[sb_off + 0xE8..sb_off + 0xEC].copy_from_slice(&head.to_le_bytes());
        for (idx, ino) in chain.iter().copied().enumerate() {
            let next = chain.get(idx + 1).copied().unwrap_or(0);
            set_test_inode_dtime(&mut image, ino, next);
        }
        // Mark orphan inodes as allocated in the inode bitmap (block 3).
        // Inode numbering is 1-based: inode N → bit (N-1) in the bitmap.
        let ibm = 3 * 4096;
        for &ino in chain {
            let bit = (ino - 1) as usize;
            image[ibm + bit / 8] |= 1 << (bit % 8);
        }
        image
    }

    #[test]
    fn read_inode_via_device() {
        let image = build_ext4_image_with_inode();
        let dev = TestDevice::from_vec(image);
        let cx = Cx::for_testing();

        let fs = OpenFs::from_device(&cx, Box::new(dev), &OpenOptions::default()).unwrap();
        let inode = fs.read_inode(&cx, InodeNumber(2)).unwrap();

        assert!(inode.is_dir());
        assert_eq!(inode.size, 4096);
        assert_eq!(inode.links_count, 2);
        assert_eq!(inode.permission_bits(), 0o755);
    }

