        let mut scope = RequestScope::empty();
        let quota = fs.get_quota_info(&cx, &mut scope).unwrap();

        assert!(!quota.user_quota_enabled);
        assert!(!quota.group_quota_enabled);
        assert!(!quota.project_quota_enabled);
