    /// Helper: open the ext4_small test fixture and enable writes.
    ///
    /// Returns None if the fixture doesn't exist (e.g. in minimal CI).
    fn open_writable_ext4() -> Option<OpenFs> {
        let path = std::path::Path::new("tests/fixtures/images/ext4_small.img");
        // Also check from the workspace root
        let path = if path.exists() {
            path.to_path_buf()
        } else {
            let ws = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
                .parent()
                .unwrap()
                .parent()
                .unwrap()
                .join("tests/fixtures/images/ext4_small.img");
            if ws.exists() {
                ws
            } else {
                return None;
            }
        };
        let cx = Cx::for_testing();
        // Copy the image so we don't mutate the fixture.
        let data = std::fs::read(&path).expect("read fixture");
        let dev = TestDevice::from_vec(data);
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Skip,
            ..OpenOptions::default()
        };
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &opts).expect("open ext4");
        fs.enable_writes(&cx).expect("enable writes");
        assert!(fs.is_writable());
        Some(fs)
    }

    /// Create a fresh ext4 image via `mkfs.ext4` and open it writable.
    ///
    /// Returns `None` if `mkfs.ext4` is not available.
    fn open_writable_ext4_mkfs(size_mb: u64) -> Option<(OpenFs, tempfile::TempDir)> {
        let tmp = tempfile::TempDir::new().expect("tmpdir");
        let image = tmp.path().join("test.ext4");
        let f = std::fs::File::create(&image).expect("create image");
        f.set_len(size_mb * 1024 * 1024).expect("set image size");
        drop(f);

        let out = std::process::Command::new("mkfs.ext4")
            .args(["-F", "-b", "4096", image.to_str().unwrap()])
            .output();
        let out = match out {
            Ok(o) if o.status.success() => o,
            _ => return None,
        };
        let _ = out; // suppress unused warning

        // Make root writable.
        let _ = std::process::Command::new("debugfs")
            .args([
                "-w",
                "-R",
                "set_inode_field / mode 040777",
                image.to_str().unwrap(),
            ])
            .output();

        let cx = Cx::for_testing();
        let data = std::fs::read(&image).expect("read image");
        let dev = TestDevice::from_vec(data);
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Apply,
            ..OpenOptions::default()
        };
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &opts).expect("open ext4");
        fs.enable_writes(&cx).expect("enable writes");
        assert!(fs.is_writable());
        Some((fs, tmp))
    }

    fn open_writable_ext4_mkfs_with_incompat_features(
        size_mb: u64,
        incompat_bits: u32,
    ) -> Option<(OpenFs, tempfile::TempDir)> {
        let tmp = tempfile::TempDir::new().expect("tmpdir");
        let image = tmp.path().join("test.ext4");
        let f = std::fs::File::create(&image).expect("create image");
        f.set_len(size_mb * 1024 * 1024).expect("set image size");
        drop(f);

        let out = std::process::Command::new("mkfs.ext4")
            .args(["-F", "-b", "4096", image.to_str().unwrap()])
            .output();
        let out = match out {
            Ok(o) if o.status.success() => o,
            _ => return None,
        };
        let _ = out;

        let _ = std::process::Command::new("debugfs")
            .args([
                "-w",
                "-R",
                "set_inode_field / mode 040777",
                image.to_str().unwrap(),
            ])
            .output();

        let mut data = std::fs::read(&image).expect("read image");
        let sb_off = EXT4_SUPERBLOCK_OFFSET;
        let incompat_off = sb_off + 0x60;
        let checksum_off = sb_off + EXT4_SB_CHECKSUM_OFFSET;
        let mut feature_incompat = u32::from_le_bytes(
            data[incompat_off..incompat_off + 4]
                .try_into()
                .expect("feature_incompat bytes"),
        );
        feature_incompat |= incompat_bits;
        data[incompat_off..incompat_off + 4].copy_from_slice(&feature_incompat.to_le_bytes());
        let checksum =
            ffs_ondisk::ext4::ext4_chksum(!0u32, &data[sb_off..sb_off + EXT4_SB_CHECKSUM_OFFSET]);
        data[checksum_off..checksum_off + 4].copy_from_slice(&checksum.to_le_bytes());

        let cx = Cx::for_testing();
        let dev = TestDevice::from_vec(data);
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Apply,
            ..OpenOptions::default()
        };
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &opts).expect("open ext4");
        fs.enable_writes(&cx).expect("enable writes");
        assert!(fs.is_writable());
        Some((fs, tmp))
    }

    /// Create a fresh ext4 image via `mkfs.ext4`, returning a clonable device
    /// handle so crash tests can snapshot in-memory bytes before reopening.
    fn open_writable_ext4_mkfs_with_device(
        size_mb: u64,
    ) -> Option<(OpenFs, TestDevice, tempfile::TempDir)> {
        let tmp = tempfile::TempDir::new().expect("tmpdir");
        let image = tmp.path().join("test.ext4");
        let f = std::fs::File::create(&image).expect("create image");
        f.set_len(size_mb * 1024 * 1024).expect("set image size");
        drop(f);

        let out = std::process::Command::new("mkfs.ext4")
            .args(["-F", "-b", "4096", image.to_str().unwrap()])
            .output();
        let out = match out {
            Ok(o) if o.status.success() => o,
            _ => return None,
        };
        let _ = out;

        let _ = std::process::Command::new("debugfs")
            .args([
                "-w",
                "-R",
                "set_inode_field / mode 040777",
                image.to_str().unwrap(),
            ])
            .output();

        let cx = Cx::for_testing();
        let data = std::fs::read(&image).expect("read image");
        let dev = TestDevice::from_vec(data);
        let snapshot = dev.clone();
        let opts = OpenOptions {
            ext4_journal_replay_mode: Ext4JournalReplayMode::Apply,
            ..OpenOptions::default()
        };
        let mut fs = OpenFs::from_device(&cx, Box::new(dev), &opts).expect("open ext4");
        fs.enable_writes(&cx).expect("enable writes");
        assert!(fs.is_writable());
        Some((fs, snapshot, tmp))
    }

