        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("xattr_roundtrip.txt"), 0o644, 0, 0)
            .expect("create");
        let ino = attr.ino;

        fs.setxattr(&cx, ino, "user.mime", b"text/plain", XattrSetMode::Set)
            .expect("setxattr create-or-replace");
