    #[test]
    fn write_rename_cross_directory() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let dir_a = fs
            .mkdir(&cx, root, OsStr::new("dir_a"), 0o755, 0, 0)
            .expect("mkdir a");
        let dir_b = fs
            .mkdir(&cx, root, OsStr::new("dir_b"), 0o755, 0, 0)
            .expect("mkdir b");

        let file = fs
            .create(&cx, dir_a.ino, OsStr::new("moved.txt"), 0o644, 0, 0)
            .expect("create in dir_a");
        fs.write(&cx, file.ino, 0, b"cross-dir").expect("write");

        // Rename from dir_a to dir_b
        fs.rename(
            &cx,
            dir_a.ino,
            OsStr::new("moved.txt"),
            dir_b.ino,
            OsStr::new("arrived.txt"),
        )
        .expect("cross-directory rename");

        // Old location gone
        let err = fs
            .lookup(&cx, dir_a.ino, OsStr::new("moved.txt"))
            .unwrap_err();
        assert_eq!(err.to_errno(), libc::ENOENT);

        // New location exists with same data
        let arrived = fs
            .lookup(&cx, dir_b.ino, OsStr::new("arrived.txt"))
            .expect("lookup in dir_b");
        assert_eq!(arrived.ino, file.ino);
        let data = fs.read(&cx, file.ino, 0, 4096).expect("read");
        assert_eq!(&data[..9], b"cross-dir");
    }

    #[test]
    fn write_rename_bumps_inode_version_but_preserves_generation() {
        let Some(fs) = open_writable_ext4() else {
            return;
        };
        let cx = Cx::for_testing();
        let root = InodeNumber(2);

        let attr = fs
            .create(&cx, root, OsStr::new("version_src.txt"), 0o644, 0, 0)
            .expect("create source");
        fs.write(&cx, attr.ino, 0, b"versioned")
            .expect("write source");

        let before = fs
            .read_inode(&cx, attr.ino)
            .expect("read inode before rename");
        let before_version = u64::from(before.version) | (u64::from(before.version_hi) << 32);
        let before_generation = before.generation;

        fs.rename(
            &cx,
            root,
            OsStr::new("version_src.txt"),
            root,
            OsStr::new("version_dst.txt"),
        )
        .expect("rename");

        let after = fs
            .read_inode(&cx, attr.ino)
            .expect("read inode after rename");
        let after_version = u64::from(after.version) | (u64::from(after.version_hi) << 32);

        assert_eq!(
            after_version,
            before_version.wrapping_add(1),
            "rename should bump ext4 i_version / change cookie exactly once"
        );
        assert_eq!(
            after.generation, before_generation,
            "rename must preserve ext4 i_generation"
        );
    }

