    #[test]
    fn btrfs_write_rename() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("old.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        ops.rename(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("old.txt"),
            InodeNumber(1),
            OsStr::new("new.txt"),
        )
        .unwrap();

        // Old name gone.
        assert!(
            ops.lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("old.txt")
            )
            .is_err()
        );
        // New name resolves to same inode.
        let found = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("new.txt"),
            )
            .unwrap();
        assert_eq!(found.ino, attr.ino);
    }

