    #[test]
    fn btrfs_write_lookup_after_rename() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        // Create a file, then rename it, verify old name gone and new name works.
        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("old.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, b"data")
            .unwrap();

        ops.rename(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("old.txt"),
            InodeNumber(1),
            OsStr::new("new.txt"),
        )
        .unwrap();

        // Old name should be gone.
        let err = ops.lookup(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("old.txt"),
        );
        assert!(err.is_err());

        // New name should resolve and file data should be intact.
        let new_attr = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("new.txt"),
            )
            .unwrap();
        assert_eq!(new_attr.ino, attr.ino);
        let data = ops
            .read(&cx, &mut RequestScope::empty(), new_attr.ino, 0, 4096)
            .unwrap();
        assert_eq!(data, b"data");
    }

    #[test]
    fn btrfs_write_xattr_set_get_list() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("xattr.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        // No xattrs initially.
        let names = ops.listxattr(&cx, attr.ino).unwrap();
        assert!(names.is_empty());
        assert_eq!(ops.getxattr(&cx, attr.ino, "user.foo").unwrap(), None);

        // Set an xattr.
        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            "user.foo",
            b"bar",
            XattrSetMode::Set,
        )
        .unwrap();

        // List should return the name.
        let names = ops.listxattr(&cx, attr.ino).unwrap();
        assert_eq!(names, vec!["user.foo"]);

        // Get should return the value.
        let val = ops.getxattr(&cx, attr.ino, "user.foo").unwrap();
        assert_eq!(val, Some(b"bar".to_vec()));

        // Non-existent xattr should return None.
        assert_eq!(ops.getxattr(&cx, attr.ino, "user.missing").unwrap(), None);
    }

    #[test]
    fn btrfs_write_xattr_set_multiple_and_remove() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("multi.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        // Set two xattrs.
        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            "user.alpha",
            b"aaa",
            XattrSetMode::Set,
        )
        .unwrap();
        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            "user.beta",
            b"bbb",
            XattrSetMode::Set,
        )
        .unwrap();

        let mut names = ops.listxattr(&cx, attr.ino).unwrap();
        names.sort();
        assert_eq!(names, vec!["user.alpha", "user.beta"]);

        // Remove one.
        let removed = ops
            .removexattr(&cx, &mut RequestScope::empty(), attr.ino, "user.alpha")
            .unwrap();
        assert!(removed);

        let names = ops.listxattr(&cx, attr.ino).unwrap();
        assert_eq!(names, vec!["user.beta"]);

        // Get the remaining one.
        assert_eq!(
            ops.getxattr(&cx, attr.ino, "user.beta").unwrap(),
            Some(b"bbb".to_vec())
        );
        assert_eq!(ops.getxattr(&cx, attr.ino, "user.alpha").unwrap(), None);
    }

