    #[test]
    fn writeback_schedule_checker_rejects_reordering_without_barrier() {
        let violations = writeback_schedule_invariant_violations(
            WritebackBarrierModel::Disabled,
            &[
                WritebackScheduleEvent::data(1, 2, 0, InodeNumber(11), 0),
                WritebackScheduleEvent::data(2, 1, 0, InodeNumber(11), 1),
            ],
        );

        assert!(violations.iter().any(|violation| {
            violation.kind == WritebackInvariantViolationKind::SourceOrderWithoutBarrier
                && violation.source_order == 2
                && violation.related_source_order == Some(1)
        }));
    }

    #[test]
    fn writeback_schedule_checker_allows_disjoint_same_epoch_reordering_with_epoch_barrier() {
        let violations = writeback_schedule_invariant_violations(
            WritebackBarrierModel::EpochFence,
            &[
                WritebackScheduleEvent::data(1, 2, 7, InodeNumber(11), 10),
                WritebackScheduleEvent::data(2, 1, 7, InodeNumber(11), 11),
                WritebackScheduleEvent::fsyncdir(3, 3, 7, InodeNumber(11)),
            ],
        );

        assert!(
            violations.is_empty(),
            "unexpected violations: {violations:?}"
        );
    }

    #[test]
    fn writeback_schedule_checker_rejects_aliased_write_reordering() {
        let violations = writeback_schedule_invariant_violations(
            WritebackBarrierModel::EpochFence,
            &[
                WritebackScheduleEvent::data(1, 2, 7, InodeNumber(11), 10),
                WritebackScheduleEvent::data(2, 1, 7, InodeNumber(11), 10),
            ],
        );

        assert!(violations.iter().any(|violation| {
            violation.kind == WritebackInvariantViolationKind::AliasedWriteReordered
                && violation.source_order == 2
                && violation.related_source_order == Some(1)
        }));
    }

    #[test]
    fn writeback_schedule_checker_rejects_metadata_ahead_of_dependent_data() {
        let violations = writeback_schedule_invariant_violations(
            WritebackBarrierModel::EpochFence,
            &[
                WritebackScheduleEvent::data(1, 2, 3, InodeNumber(55), 0),
                WritebackScheduleEvent::metadata(2, 1, 3, InodeNumber(2), Some(InodeNumber(55))),
            ],
        );

        assert!(violations.iter().any(|violation| {
            violation.kind == WritebackInvariantViolationKind::MetadataAheadOfDependentData
                && violation.source_order == 2
                && violation.related_source_order == Some(1)
        }));
    }

    #[test]
    fn writeback_schedule_checker_rejects_fsync_before_prior_epoch_delivery() {
        let violations = writeback_schedule_invariant_violations(
            WritebackBarrierModel::EpochFence,
            &[
                WritebackScheduleEvent::data(1, 2, 9, InodeNumber(77), 0),
                WritebackScheduleEvent::fsync(2, 1, 9, InodeNumber(77)),
            ],
        );

        assert!(violations.iter().any(|violation| {
            violation.kind == WritebackInvariantViolationKind::SyncBoundaryBeforePriorWrites
                && violation.source_order == 2
                && violation.related_source_order == Some(1)
        }));
    }

    #[test]
    fn writeback_schedule_checker_rejects_flush_as_durability_boundary() {
        let violations = writeback_schedule_invariant_violations(
            WritebackBarrierModel::EpochFence,
            &[WritebackScheduleEvent::flush(1, 1, InodeNumber(88), true)],
        );

        assert_eq!(
            violations,
            vec![WritebackInvariantViolation {
                kind: WritebackInvariantViolationKind::FlushAdvancedDurability,
                source_order: 1,
                related_source_order: None,
            }]
        );
    }

    // ── WritebackEpochBarrier tests ──────────────────────────────────────

    #[test]
    fn epoch_barrier_disabled_is_noop() {
        let mut barrier = WritebackEpochBarrier::new();
        assert!(!barrier.is_enabled());
        // All operations are no-ops when disabled.
        barrier.stage_write(InodeNumber(1));
        barrier.commit_inode(InodeNumber(1));
        assert!(barrier.mark_durable(InodeNumber(1)).is_ok());
        assert!(barrier.is_epoch_visible(InodeNumber(1), 999));
        assert_eq!(barrier.tracked_inode_count(), 0);
    }

    #[test]
    fn epoch_barrier_untracked_inode_is_visible() {
        let barrier = WritebackEpochBarrier::enabled();
        // An inode that was never staged (predates writeback-cache) should
        // be visible at any epoch — its data was committed via the direct path.
        let untracked = InodeNumber(999);
        assert!(barrier.is_epoch_visible(untracked, 0));
        assert!(barrier.is_epoch_visible(untracked, 1));
        assert!(barrier.is_epoch_visible(untracked, 100));
    }

    #[test]
    fn epoch_barrier_stage_and_commit_cycle() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(42);

        // Stage a write.
        barrier.stage_write(inode);
        let state = barrier.inode_state(inode).expect("inode tracked");
        assert_eq!(state.staged_epoch, 1);
        assert_eq!(state.visible_epoch, 0);
        assert!(state.has_pending_visibility());
        assert!(!barrier.is_epoch_visible(inode, 1));

        // Commit makes it visible.
        barrier.commit_inode(inode);
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.visible_epoch, 1);
        assert!(barrier.is_epoch_visible(inode, 1));
        assert!(state.has_pending_durability());

        // Mark durable.
        barrier.mark_durable(inode).expect("durable");
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.durable_epoch, 1);
        assert!(!state.has_pending_durability());
    }

    #[test]
    fn epoch_barrier_fsync_commits_and_durables() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(10);
        barrier.stage_write(inode);
        barrier.fsync_barrier(inode).expect("fsync");
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.visible_epoch, 1);
        assert_eq!(state.durable_epoch, 1);
        assert!(state.is_valid());
    }

    #[test]
    fn epoch_barrier_commit_at_higher_epoch_advances_to_staged() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(5);

        // Stage at epoch 1, then advance to epoch 2.
        barrier.stage_write(inode); // staged at epoch 1
        let _epoch2 = barrier.advance_epoch(); // now epoch 2

        // Commit at epoch 2 should succeed — the inode has no epoch-2 writes,
        // so visibility advances to staged_epoch (1), not current_epoch (2).
        barrier.commit_inode(inode);
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.staged_epoch, 1);
        assert_eq!(state.visible_epoch, 1);
        assert!(state.is_valid());
    }

    #[test]
    fn epoch_barrier_mark_durable_before_visible_fails() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(5);

        // Stage at epoch 1 but don't commit.
        barrier.stage_write(inode);
        // mark_durable should fail because visible_epoch is still 0.
        let result = barrier.mark_durable(inode);
        // mark_durable uses visible_epoch (0), so epoch=0 > durable(0) is false → Ok (no-op).
        // Actually, let's verify: mark_durable reads state.visible_epoch=0,
        // then checks epoch(0) > visible(0) → false → no error, no advance. ✓
        assert!(result.is_ok());
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.durable_epoch, 0);
    }

    #[test]
    fn epoch_barrier_multi_epoch_advances() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(7);

        // Epoch 1: stage and commit.
        barrier.stage_write(inode);
        barrier.fsync_barrier(inode).unwrap();

        // Advance to epoch 2.
        barrier.advance_epoch();
        assert_eq!(barrier.current_epoch(), 2);

        // Epoch 2: stage and commit.
        barrier.stage_write(inode);
        barrier.fsync_barrier(inode).unwrap();
        let state = barrier.inode_state(inode).unwrap();
        assert_eq!(state.staged_epoch, 2);
        assert_eq!(state.visible_epoch, 2);
        assert_eq!(state.durable_epoch, 2);
    }

    #[test]
    fn epoch_barrier_invariant_always_holds() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(99);
        barrier.stage_write(inode);
        let state = barrier.inode_state(inode).unwrap();
        assert!(state.is_valid());
        barrier.commit_inode(inode);
        assert!(barrier.inode_state(inode).unwrap().is_valid());
        barrier.mark_durable(inode).expect("durable");
        assert!(barrier.inode_state(inode).unwrap().is_valid());
    }

    // ── Writeback benchmark tests ────────────────────────────────────────

    #[test]
    fn writeback_benchmark_all_workloads_complete() {
        for workload in WritebackWorkload::ALL {
            let disabled = run_writeback_barrier_benchmark(workload, false);
            let enabled = run_writeback_barrier_benchmark(workload, true);

            assert_eq!(disabled.operations, workload.operation_count());
            assert_eq!(enabled.operations, workload.operation_count());
            assert!(!disabled.writeback_enabled);
            assert!(enabled.writeback_enabled);
            assert_eq!(disabled.epoch_transitions, 0); // Disabled → no epochs.
            // Enabled should have some epoch transitions.
            if workload.write_count() > 0 {
                assert!(
                    enabled.epoch_transitions > 0 || enabled.fsync_barriers > 0,
                    "{workload:?}: expected epoch transitions when enabled"
                );
            }
        }
    }

    #[test]
    fn writeback_benchmark_comparison_produces_valid_ratios() {
        for workload in WritebackWorkload::ALL {
            let baseline = run_writeback_barrier_benchmark(workload, false);
            let writeback = run_writeback_barrier_benchmark(workload, true);
            let cmp = WritebackComparison::compare(baseline, writeback);

            assert!(cmp.throughput_ratio > 0.0);
            assert!(cmp.throughput_ratio.is_finite());
            assert!(cmp.latency_p50_ratio.is_finite());
            assert!(cmp.latency_p95_ratio.is_finite());
            assert_eq!(cmp.workload, workload);

            eprintln!(
                "  {:20} throughput_ratio={:.3} p50_ratio={:.3} p95_ratio={:.3} \
                 epoch_transitions={}",
                workload.name(),
                cmp.throughput_ratio,
                cmp.latency_p50_ratio,
                cmp.latency_p95_ratio,
                cmp.writeback.epoch_transitions,
            );
        }
    }

    #[test]
    fn writeback_benchmark_disabled_has_zero_overhead() {
        let result = run_writeback_barrier_benchmark(WritebackWorkload::SmallWrites, false);
        assert_eq!(result.epoch_transitions, 0);
        assert_eq!(result.fsync_barriers, 0);
        assert!(!result.writeback_enabled);
    }

    // ── Crash consistency matrix for writeback epoch barrier ─────────────
    //
    // Each scenario simulates a crash at a specific point in the writeback
    // lifecycle and verifies the epoch state invariants hold after "recovery"
    // (i.e., constructing a fresh barrier from the last known durable state).

    /// Simulate recovery by creating a fresh barrier whose state reflects
    /// what was durable before the crash.
    fn recover_barrier(pre_crash: &WritebackEpochBarrier) -> WritebackEpochBarrier {
        let mut recovered = if pre_crash.is_enabled() {
            WritebackEpochBarrier::enabled()
        } else {
            WritebackEpochBarrier::new()
        };
        // After crash, only durable state survives. Staged and visible
        // epochs that weren't synced are lost.
        for (&inode, state) in &pre_crash.inodes {
            let durable = state.durable_epoch;
            recovered.inodes.insert(
                inode,
                InodeEpochState {
                    staged_epoch: durable,
                    visible_epoch: durable,
                    durable_epoch: durable,
                },
            );
        }
        recovered.current_epoch = pre_crash.current_epoch;
        recovered
    }

    /// Verify that all inodes in the barrier satisfy the monotonicity invariant
    /// and no partial epochs are visible.
    fn verify_crash_recovery_invariants(barrier: &WritebackEpochBarrier, scenario: &str) {
        for (&inode, state) in &barrier.inodes {
            assert!(
                state.is_valid(),
                "invariant violated after {scenario}: inode={inode:?} state={state:?}"
            );
            // No partial visibility: visible must equal durable after recovery.
            assert_eq!(
                state.visible_epoch, state.durable_epoch,
                "partial epoch visible after {scenario}: inode={inode:?} state={state:?}"
            );
        }
    }

    #[test]
    fn crash_01_during_buffered_write_before_epoch_commit() {
        let mut b = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(1);
        b.stage_write(inode);
        // Crash here: staged but never committed or synced.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_01_buffered_write");
        // After recovery, nothing should be visible (durable was 0).
        let state = r.inode_state(inode).unwrap();
        assert_eq!(state.visible_epoch, 0);
    }

    #[test]
    fn crash_02_after_commit_before_device_sync() {
        let mut b = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(2);
        b.stage_write(inode);
        b.commit_inode(inode); // Visible but not yet durable.
        // Crash here: visible_epoch=1 but durable_epoch=0.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_02_commit_no_sync");
        let state = r.inode_state(inode).unwrap();
        // Recovery resets to durable (0) — the committed data is lost.
        assert_eq!(state.visible_epoch, 0);
        assert_eq!(state.durable_epoch, 0);
    }

    #[test]
    fn crash_03_after_fsync_completes() {
        let mut b = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(3);
        b.stage_write(inode);
        b.fsync_barrier(inode).unwrap();
        // Crash here: everything was synced → data survives.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_03_after_fsync");
        let state = r.inode_state(inode).unwrap();
        assert_eq!(state.durable_epoch, 1);
        assert_eq!(state.visible_epoch, 1);
    }

    #[test]
    fn crash_04_during_epoch_advance() {
        let mut b = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(4);
        b.stage_write(inode);
        b.fsync_barrier(inode).unwrap(); // Epoch 1 fully durable.
        b.advance_epoch(); // Epoch 2.
        b.stage_write(inode); // Staged at epoch 2 but not committed.
        // Crash here: epoch 2 writes lost, epoch 1 survives.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_04_epoch_advance");
        let state = r.inode_state(inode).unwrap();
        assert_eq!(state.durable_epoch, 1);
    }

    #[test]
    fn crash_05_concurrent_inodes_partial_sync() {
        let mut b = WritebackEpochBarrier::enabled();
        let a = InodeNumber(10);
        let c = InodeNumber(11);
        b.stage_write(a);
        b.stage_write(c);
        // Inode A fsyncs, inode C doesn't.
        b.fsync_barrier(a).unwrap();
        // Crash: A is durable, C is not.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_05_partial_sync");
        assert_eq!(r.inode_state(a).unwrap().durable_epoch, 1);
        assert_eq!(r.inode_state(c).unwrap().durable_epoch, 0);
    }

    #[test]
    fn crash_06_multiple_writes_single_epoch() {
        let mut b = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(6);
        // Multiple writes in the same epoch.
        for _ in 0..5 {
            b.stage_write(inode);
        }
        // All staged at epoch 1 (stage_write takes max).
        assert_eq!(b.inode_state(inode).unwrap().staged_epoch, 1);
        // Crash before commit: all 5 writes lost.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_06_multi_write");
        assert_eq!(r.inode_state(inode).unwrap().durable_epoch, 0);
    }

    #[test]
    fn crash_07_fsync_then_more_writes_then_crash() {
        let mut b = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(7);
        b.stage_write(inode);
        b.fsync_barrier(inode).unwrap(); // Epoch 1 durable.
        b.advance_epoch();
        b.stage_write(inode); // Epoch 2 staged.
        b.commit_inode(inode); // Epoch 2 visible but NOT durable.
        // Crash: epoch 1 data survives, epoch 2 data lost.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_07_post_fsync_writes");
        let state = r.inode_state(inode).unwrap();
        assert_eq!(state.durable_epoch, 1);
        assert_eq!(state.visible_epoch, 1);
    }

    #[test]
    fn crash_08_interleaved_epochs_three_inodes() {
        let mut barrier = WritebackEpochBarrier::enabled();
        let ino_alpha = InodeNumber(20);
        let ino_beta = InodeNumber(21);
        let ino_gamma = InodeNumber(22);

        // Epoch 1: all three write.
        barrier.stage_write(ino_alpha);
        barrier.stage_write(ino_beta);
        barrier.stage_write(ino_gamma);
        barrier.fsync_barrier(ino_alpha).unwrap(); // alpha durable at 1.
        barrier.fsync_barrier(ino_beta).unwrap(); // beta durable at 1.
        // gamma not fsynced.

        barrier.advance_epoch(); // Epoch 2.
        barrier.stage_write(ino_alpha);
        barrier.fsync_barrier(ino_alpha).unwrap(); // alpha durable at 2.
        barrier.stage_write(ino_gamma); // gamma staged at 2, still not durable from epoch 1!

        // Crash: alpha has epoch 2, beta has epoch 1, gamma has nothing durable.
        let recovered = recover_barrier(&barrier);
        verify_crash_recovery_invariants(&recovered, "crash_08_interleaved");
        assert_eq!(recovered.inode_state(ino_alpha).unwrap().durable_epoch, 2);
        assert_eq!(recovered.inode_state(ino_beta).unwrap().durable_epoch, 1);
        assert_eq!(recovered.inode_state(ino_gamma).unwrap().durable_epoch, 0);
    }

    #[test]
    fn crash_09_rapid_epoch_advances_no_writes() {
        let mut b = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(9);
        b.stage_write(inode);
        b.fsync_barrier(inode).unwrap();
        // Rapidly advance epochs without any writes.
        for _ in 0..10 {
            b.advance_epoch();
        }
        // Crash: only epoch 1 was ever durable.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_09_rapid_advance");
        assert_eq!(r.inode_state(inode).unwrap().durable_epoch, 1);
    }

    #[test]
    fn crash_10_commit_at_higher_epoch_than_staged() {
        let mut b = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(10);
        b.stage_write(inode); // Staged at epoch 1.
        b.advance_epoch(); // Epoch 2.
        // Commit at epoch 2 (inode only staged at 1) → advances visible to 1.
        b.commit_inode(inode);
        let state = b.inode_state(inode).unwrap();
        assert_eq!(state.visible_epoch, 1);
        // But NOT durable — crash loses it.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_10_higher_epoch_commit");
        assert_eq!(r.inode_state(inode).unwrap().durable_epoch, 0);
    }

    #[test]
    fn crash_11_disabled_barrier_always_consistent() {
        let b = WritebackEpochBarrier::new(); // Disabled.
        let r = recover_barrier(&b);
        // No inodes tracked in disabled mode → trivially consistent.
        assert_eq!(r.tracked_inode_count(), 0);
    }

    #[test]
    fn crash_12_all_scenarios_maintain_monotonicity() {
        // Meta-test: run through a complex sequence and verify invariant
        // holds at every step and after recovery.
        let mut b = WritebackEpochBarrier::enabled();
        let inodes: Vec<InodeNumber> = (100..110).map(InodeNumber).collect();

        for epoch_round in 0..5_u64 {
            for &inode in &inodes {
                b.stage_write(inode);
            }
            // Fsync half the inodes.
            for &inode in &inodes[..5] {
                b.fsync_barrier(inode).unwrap();
            }
            // Verify all inodes valid mid-round.
            for (&_inode, state) in &b.inodes {
                assert!(state.is_valid(), "mid-round {epoch_round}");
            }
            b.advance_epoch();
        }

        // Crash at end: only fsynced inodes have durable data.
        let r = recover_barrier(&b);
        verify_crash_recovery_invariants(&r, "crash_12_complex_sequence");
        for &inode in &inodes[..5] {
            assert!(r.inode_state(inode).unwrap().durable_epoch > 0);
        }
        for &inode in &inodes[5..] {
            assert_eq!(r.inode_state(inode).unwrap().durable_epoch, 0);
        }
    }

    // ── Verification Gate: bd-m5wf.2.5 — writeback-cache epic ────────────

    /// Comprehensive verification gate for the writeback-cache epic.
    ///
    /// Verifies all acceptance criteria:
    /// 1. Crash matrix: all 12 scenarios covered (verified by running them)
    /// 2. MVCC snapshot isolation: deferred visibility works correctly
    /// 3. Performance: benchmark framework operational
    /// 4. No regressions: disabled mode is a true no-op
    /// 5. Design: invariant checker tests pass
    #[test]
    fn verification_gate_writeback_cache_epic() {
        eprintln!("=== Verification Gate: Writeback-Cache Epic (bd-m5wf.2.5) ===");

        // ── 1. Epoch barrier state machine correctness ──
        let mut barrier = WritebackEpochBarrier::enabled();
        let inode = InodeNumber(1);

        // Stage → not visible.
        barrier.stage_write(inode);
        assert!(!barrier.is_epoch_visible(inode, 1));
        assert!(barrier.inode_state(inode).unwrap().has_pending_visibility());

        // Commit → visible but not durable.
        barrier.commit_inode(inode);
        assert!(barrier.is_epoch_visible(inode, 1));
        assert!(barrier.inode_state(inode).unwrap().has_pending_durability());

        // Fsync → durable.
        barrier.mark_durable(inode).unwrap();
        let state = barrier.inode_state(inode).unwrap();
        assert!(!state.has_pending_visibility());
        assert!(!state.has_pending_durability());
        assert!(state.is_valid());
        eprintln!("  [PASS] Epoch barrier state machine: stage → commit → durable");

        // ── 2. Deferred visibility preserves MVCC isolation ──
        barrier.advance_epoch();
        barrier.stage_write(inode);
        // Epoch 2 staged but NOT committed → not visible.
        assert!(barrier.is_epoch_visible(inode, 1)); // Epoch 1 still visible.
        assert!(!barrier.is_epoch_visible(inode, 2)); // Epoch 2 not yet.
        // Untracked inodes are always visible.
        assert!(barrier.is_epoch_visible(InodeNumber(999), 100));
        eprintln!("  [PASS] Deferred visibility preserves MVCC isolation");

        // ── 3. Crash recovery: verify monotonicity ──
        let recovered = recover_barrier(&barrier);
        verify_crash_recovery_invariants(&recovered, "verification_gate");
        // Only epoch 1 was durable.
        let rec_state = recovered.inode_state(inode).unwrap();
        assert_eq!(rec_state.durable_epoch, 1);
        assert_eq!(rec_state.visible_epoch, 1);
        assert_eq!(rec_state.staged_epoch, 1);
        eprintln!("  [PASS] Crash recovery: monotonicity preserved, partial epochs lost");

        // ── 4. Disabled mode is a true no-op ──
        let mut disabled = WritebackEpochBarrier::new();
        assert!(!disabled.is_enabled());
        disabled.stage_write(InodeNumber(1));
        disabled.commit_inode(InodeNumber(1));
        assert!(disabled.mark_durable(InodeNumber(1)).is_ok());
        assert!(disabled.is_epoch_visible(InodeNumber(1), 999));
        assert_eq!(disabled.tracked_inode_count(), 0);
        eprintln!("  [PASS] Disabled mode: zero tracking overhead");

        // ── 5. Benchmark framework operational ──
        let baseline = run_writeback_barrier_benchmark(WritebackWorkload::SmallWrites, false);
        let enabled = run_writeback_barrier_benchmark(WritebackWorkload::SmallWrites, true);
        assert!(baseline.total_duration_us > 0);
        assert!(enabled.total_duration_us > 0);
        assert_eq!(baseline.epoch_transitions, 0);
        assert!(enabled.epoch_transitions > 0);
        let cmp = WritebackComparison::compare(baseline, enabled);
        assert!(cmp.throughput_ratio > 0.0);
        assert!(cmp.throughput_ratio.is_finite());
        eprintln!(
            "  [PASS] Benchmark: throughput_ratio={:.3} (barrier overhead measured)",
            cmp.throughput_ratio
        );

        // ── 6. Cross-epoch fence correctness ──
        let mut fence_barrier = WritebackEpochBarrier::enabled();
        let ino_a = InodeNumber(100);
        let ino_b = InodeNumber(101);
        fence_barrier.stage_write(ino_a); // Epoch 1.
        fence_barrier.advance_epoch(); // Epoch 2.
        fence_barrier.stage_write(ino_b); // Epoch 2.
        // Commit ino_a at epoch 2 — should advance to min(2, staged=1) = 1.
        fence_barrier.commit_inode(ino_a);
        assert_eq!(fence_barrier.inode_state(ino_a).unwrap().visible_epoch, 1);
        // Commit ino_b at epoch 2 — should advance to min(2, staged=2) = 2.
        fence_barrier.commit_inode(ino_b);
        assert_eq!(fence_barrier.inode_state(ino_b).unwrap().visible_epoch, 2);
        eprintln!("  [PASS] Cross-epoch fence: min(current, staged) semantics correct");

        eprintln!("VERIFICATION GATE PASSED: writeback-cache epic complete");
    }

