        let mut alloc = alloc_mutex.lock();
        let parent_oid = 256;
        let dir_item = BtrfsDirItem {
            child_objectid: 9001,
            child_key_type: BTRFS_ITEM_INODE_ITEM,
            child_key_offset: 0,
            file_type: BTRFS_FT_REG_FILE,
            name: b"present.txt".to_vec(),
        };
        fs.btrfs_insert_dir_entry(&mut alloc, parent_oid, &dir_item)
